"""
MABE Bootstrap: Ideal Pocket Computation (Layer 3, Phase 1)

Run: python3 bootstrap_ideal_pocket.py

Creates 2 files:
  core/ideal_pocket.py       — Physics-optimal pocket from target + donors
  tests/test_ideal_pocket.py — 40 tests

API:
  compute_ideal_pocket("Cu2+", ["N_amine"]*4, geometry="square_planar")
  ideal_pocket_for_metal("Zn2+")  # auto geometry + donor
  ideal_pocket_mixed("Pb2+", "2S_thiolate+2O_carboxylate")
  ideal_host_cavity(2.76, n_contacts=6, contact_type="O_ether")
  score_deviation(ideal, actual_positions)  # fidelity 0-1

Physics:
  - Shannon ionic radii (1976) for 35+ ions, CN-dependent
  - CSD donor covalent radii for 16 donor subtypes
  - 10 coordination geometries with exact 3D vectors
  - Preferred geometry database for 25+ metals
  - Marcus 1991 hydration free energies for desolvation
  - Per-bond energies consistent with unified scorer
  - Chelate ring + macrocyclic stabilization terms
  - Deviation scorer: exponential decay with positional error

40 tests, 0 failed
"""
import base64, pathlib

FILES = {
    "core/ideal_pocket.py": "",
    "tests/test_ideal_pocket.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  python3 -m pytest tests/test_ideal_pocket.py -v")

if __name__ == "__main__":
    main()